                 // Module level: wrap with ( ... catch unreachable)
@@ -2419,7 +2452,8 @@ pub fn genCall(self: *NativeCodegen, call: ast.Node.Call) CodegenError!void {

         // For user-defined functions: inject allocator as FIRST argument
