@@ -2521,6 +2555,14 @@ pub fn genCall(self: *NativeCodegen, call: ast.Node.Call) CodegenError!void {
                 // Check if argument is a class instance - pass by pointer for Python semantics
                 const arg_type = self.inferExprScoped(arg) catch .unknown;
                 if (type_traits.isClassInstance(arg_type)) {
+                    // For array.array passed to anytype callable, extract .tobytes() for []const u8 compatibility
+                    // This handles cases like: f(array('B', data)) where f expects bytes
+                    const is_array_array = std.mem.eql(u8, arg_type.class_instance, "array.array");
+                    if (is_anytype_callable and is_array_array) {
+                        try genExpr(self, arg);
+                        try self.emit(".tobytes()");
+                        continue;
+                    }
                     // Don't add & for renamed variables (param reassignment creates var, already a value)
                     const is_renamed_var = if (arg == .name)
                         self.var_renames.contains(arg.name.id)
@@ -2544,6 +2586,19 @@ pub fn genCall(self: *NativeCodegen, call: ast.Node.Call) CodegenError!void {
                     try genExpr(self, arg);
                     continue;
                 }
+
+                // When passing PyBytes as an argument, unwrap to []const u8
+                // Most functions (stdlib, user-defined) expect []const u8, not PyBytes
+                // This handles:
+                // - anytype callable (like f where f is &base64.b64encode)
+                // - generated methods like check_nonbyte_element_format(f, data)
+                // - any other function call where bytes are passed
+                if (arg_type == .bytes) {
+                    try genExpr(self, arg);
+                    try self.emit(".data");
+                    continue;
+                }
+
                 try genExpr(self, arg);
             }

@@ -1808,6 +1808,29 @@ fn genMethodBodyWithAllocatorInfoAndContext(
     // Clear local variable types (new method scope)
     self.clearLocalVarTypes();

+    // Store parameter types from function_call_args so inferExprScoped can find them
+    // This enables proper type checking when parameters are passed to other methods
+    // Build qualified method name: ClassName.methodName
+    if (self.current_class_name) |class_name| {
+        var method_key_buf: [256]u8 = undefined;
+        const method_key = std.fmt.bufPrint(&method_key_buf, "{s}.{s}", .{ class_name, method.name }) catch null;
+        if (method_key) |key| {
+            if (self.type_inferrer.function_call_args.get(key)) |param_types| {
+                // Store each parameter's type (skip self which is index 0)
+                // method.args doesn't include self for methods, so param_types[i] = method.args[i]
+                for (method.args, 0..) |arg, i| {
+                    // Skip 'self' parameter
+                    if (std.mem.eql(u8, arg.name, "self")) continue;
+                    // Get corresponding type from call args (offset by 1 for self)
+                    const type_idx = if (i == 0) 0 else i - 1;
+                    if (type_idx < param_types.len) {
+                        self.setLocalVarType(arg.name, param_types[type_idx]) catch {};
+                    }
+                }
+            }
+        }
+    }
+
     // Track parameters that were renamed to avoid method shadowing (e.g., init -> init_arg)
     // We'll restore these when exiting the method
     var renamed_params = std.ArrayListUnmanaged([]const u8){};
